    "cases.run_a_toolbox_talk_and_record_attendance.step.pick-activity.out.activity": "Activitate cu risc ridicat selectată",
    "cases.run_a_toolbox_talk_and_record_attendance.step.pick-activity.out.hazard": "Pericol principal identificat",
